ALTER TABLE MELANBIDE90_FACTURAS 
ADD (
	IMPORTEVALI NUMBER(10, 2),
	VALIDADA VARCHAR2(1),
	IVASUB VARCHAR2(1),
	MOTNOVAL VARCHAR2(2)
	);

COMMENT ON COLUMN MELANBIDE90_FACTURAS.VALIDADA IS 'FACTURA VALIDADA';
COMMENT ON COLUMN MELANBIDE90_FACTURAS.IMPORTEVALI IS 'IMPORTE VALIDADO';
COMMENT ON COLUMN MELANBIDE90_FACTURAS.IVASUB IS 'IVA SUBVENCIONABLE';
COMMENT ON COLUMN MELANBIDE90_FACTURAS.MOTNOVAL IS 'MOTIVO NO VALIDACIÓN';

-- Importes Máximos por ejercicio
  create table "MELANBIDE90_IMPORTES_EJE" 
   (	"EJERCICIO" NUMBER(4,0) not null ENABLE, 
	"MAX_FAMILIA" NUMBER(8,2) not null enable, 
	"MAX_MINIMIS" number(9,2) not nulL ENABLE, 
	 constraint "MELANBIDE90_IMPORTES_EJE_PK" primary key ("EJERCICIO")
  using index  ENABLE
   ) ;

   COMMENT ON COLUMN "MELANBIDE90_IMPORTES_EJE"."EJERCICIO" IS 'Ejercicio';
   COMMENT ON COLUMN "MELANBIDE90_IMPORTES_EJE"."MAX_FAMILIA" IS 'Importe mámimo por Familia';
   COMMENT ON COLUMN "MELANBIDE90_IMPORTES_EJE"."MAX_MINIMIS" IS 'Importe mámimo Minimis';




