-- AGRUPACIONES
update E_PCA_GROUP set PCA_DESC_GROUP ='FAMILIA 1' where PCA_ID_GROUP='GFAM' and PCA_PRO='ININ';

-- SUPLEMENTARIOS
update E_PCA set PCA_DES = 'FAMILIA', PCA_ROT = 'FAMILIA' where pca_pro = 'ININ' and PCA_GROUP = 'GFAM' and PCA_COD ='FAMILIA1';
update E_PCA set PCA_GROUP = 'GFAM2', PCA_DES = 'FAMILIA', PCA_ROT = 'FAMILIA' where pca_pro = 'ININ' and PCA_GROUP = 'GFAM' and PCA_COD ='FAMILIA2';
update E_PCA set PCA_GROUP = 'GFAM3', PCA_DES = 'FAMILIA', PCA_ROT = 'FAMILIA' where pca_pro = 'ININ' and PCA_GROUP = 'GFAM' and PCA_COD ='FAMILIA3';
update E_PCA set PCA_GROUP = 'ANTE' where pca_pro = 'ININ' and PCA_GROUP = 'GFAM' and PCA_COD ='TIPGASTO1';
update E_PCA set PCA_GROUP = 'ANTE' where pca_pro = 'ININ' and PCA_GROUP = 'GFAM' and PCA_COD ='TIPGASTO2';
update E_PCA set PCA_GROUP = 'ANTE' where pca_pro = 'ININ' and PCA_GROUP = 'GFAM' and PCA_COD ='TIPGASTO3';

UPDATE "E_PCA" SET PCA_PLT = '6', PCA_TDA = '6', PCA_TAM = '1', PCA_DESPLEGABLE = 'SN01', PCA_BLOQ = 'SI' WHERE PCA_PRO ='ININ' and PCA_COD in ('OPOSVERIAUTOHHFF','OPOSVERIAUTOTGSS');
select * from e_txt where txt_num like '%/ININ/%' and txt_cod in ('OPOSVERIAUTOHHFF','OPOSVERIAUTOTGSS');
